var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"대형 침식체 무력화 확인!","JPN":"大型の侵食体、無力化を確認！","ENG":"Large C.O. has been eliminated!","TWN":"確認大型侵蝕體失去攻擊性！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"측면의 기세도 눈에 띄게 약해졌다! 대열 정리하고 침착하게 대응해!","JPN":"側面の勢いも目に見えて弱くなっている！　隊列を整え、落ち着いて対応しろ！","ENG":"The forces on the sides have also got noticeably weaker! Maintain your formation and avoid making hasty decisions!","TWN":"側面的氣勢也明顯减弱！整軍後冷靜應對！"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"대장님. 더 이상 적이 몰려오지 않습니다.","JPN":"隊長。もう敵が押し寄せてきません。","ENG":"Captain. They're no longer coming at us.","TWN":"隊長，敵人攻勢減緩。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이상하군.","JPN":"妙だな。","ENG":"That's odd.","TWN":"奇怪。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"네?","JPN":"はい？","ENG":"Sorry?","TWN":"嗯？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이 침식체들을 불러들인 놈이 모습을 드러내지 않았다.","JPN":"この侵食体を呼び寄せたやつが姿を現していない。","ENG":"We haven't found the person who summoned the C.O.s here.","TWN":"引來這些侵蝕體的傢伙竟然沒有露面。"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"침식체의 대부분을 처리했는데도 모습을 드러내지 않았다는 건……","JPN":"侵食体のほとんどを倒したのに現れていないということは……","ENG":"We killed most of them. but seeing how she hasn't shown herself...","TWN":"我們已經除掉大部分的侵蝕體，她卻沒有出現……"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…설마?","JPN":"……まさか？","ENG":"I got a bad feeling about this...","TWN":"…難道？"},"stage":{"bg":"NOMAD_VILLAGE","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"사방의 숲이 전부 비슷하게 생겼는데, 제대로 가고 있는 게 맞나?","JPN":"周辺の森はすべて同じに見えるんだが、ちゃんと進んでいるのか？","ENG":"All I see is trees and grass. Are you sure we're going the right way?","TWN":"四周的樹林都長得好像，這樣走沒錯吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"걱정 마십시오. 저희들이 오랫동안 다니던 지름길입니다.","JPN":"ご心配なさいますな。わしらが長い間使ってきた近道です。","ENG":"No need to worry. This is a shortcut we've been using for a long time.","TWN":"你放心吧，我們一直以來都是走這條小路的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"이대로 가다 보면 곧 도시가…","JPN":"このまままっすぐ行けばすぐ都市が……","ENG":"If we keep heading in this direction, a city should appear soo─","TWN":"繼續直走就會看到都市……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"…음?","JPN":"……む？","ENG":"Mm?","TWN":"…嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"왜 그러지?","JPN":"どうした？","ENG":"What's wrong?","TWN":"怎麼了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"이상하군요. 오래 전부터 이곳에 있던 부러진 나무가 보이지 않습니다.","JPN":"おかしいのう。昔からここにあった折れた木が見当たりません。","ENG":"Strange... I can’t see the broken tree that should be here.","TWN":"奇怪，怎麼沒看到很久之前就在這裡的樹枝。 "},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"촌장님, 이것 보세요. 저희가 방금 전에 부러뜨렸던 나뭇가지입니다.","JPN":"村長、これを見てください。私たちがさっき折った木の枝です。","ENG":"Chief, come look at this. This is a branch we just broke off.","TWN":"村長，你看，這是我們剛才折斷的樹枝。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"NOMAD_BORDER_NULL_ADULT","text":{"KOREA":"믿기지 않지만…… 같은 곳을 맴돈 것 같아요.","JPN":"信じられませんが……同じところをぐるぐる回ってたみたいです。","ENG":"I don't want to believe it, but... I think we're going around in circles.","TWN":"真不敢相信……我們好像在鬼打牆。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"그럴 리가……","JPN":"そんなはずは……","ENG":"It cannot be...","TWN":"怎麼會……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}}]`);export{e as default};